// Loads the curated exercise dataset (1324 entries, English source fields).
// Images: 320 animated GIFs + 1324 static JPGs in /public/exercises.
// We map the dataset to a stable shape and resolve image URLs at runtime.
import raw from '../../public/exercises-meta.json'
// The actually-present GIF filenames (generated by prebuild.cjs). Used so the
// runtime only requests GIFs that exist — avoiding 404s for the 1004
// exercises that have no animated demo (which otherwise slow the page).
import gifList from './gifList.json'

export const EXERCISES = raw

// Set of present GIF basenames for O(1) lookup.
export const GIF_SET = new Set(gifList)

// Build fast lookups
export const BY_ID = Object.fromEntries(EXERCISES.map((e) => [e.id, e]))

export const CATEGORIES = Array.from(
  new Set(EXERCISES.map((e) => e.category))
).sort()

export const BODY_PARTS = Array.from(
  new Set(EXERCISES.map((e) => e.body_part))
).sort()

export const EQUIPMENT = Array.from(
  new Set(EXERCISES.map((e) => e.equipment))
).sort()

export function getById(id) {
  return BY_ID[id]
}

// Does a GIF actually exist on disk for this exercise?
export function hasGif(exercise) {
  if (!exercise || !exercise.gif) return false
  const base = exercise.gif.startsWith('/') ? exercise.gif.slice(1) : exercise.gif
  return GIF_SET.has(base)
}

// Resolve the BEST image for an exercise: prefer the animated GIF (only if it
// physically exists), then the static JPG (every exercise has one). Returns an
// array of candidate URLs (most-preferred first) so the cache can cascade.
export function imageCandidates(exercise) {
  if (!exercise) return []
  const out = []
  // GIF gives animation where we actually have it
  if (hasGif(exercise)) {
    const g = exercise.gif.startsWith('/') ? exercise.gif : `/exercises/${exercise.gif}`
    out.push(g)
  }
  // JPG is the universal fallback (every exercise has one)
  if (exercise.image) {
    const j = exercise.image.startsWith('/') ? exercise.image : `/exercises/${exercise.image}`
    out.push(j)
  }
  return out
}
